import React, { useState, useEffect, useRef } from "react";
import io from "socket.io-client";
import axios from "axios";
import "./App.css";

const SERVER_URL = process.env.REACT_APP_SERVER_URL || "http://localhost:3001";
const socket = io(SERVER_URL, { transports: ["websocket"] });

function App() {
  const [username, setUsername] = useState(null);
  const [room, setRoom] = useState("global");
  const [newRoom, setNewRoom] = useState("");
  const [token, setToken] = useState(null);
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [form, setForm] = useState({ username: "", email: "", password: "" });
  const [mode, setMode] = useState("login");
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [typingUser, setTypingUser] = useState(null);
  const typingTimeoutRef = useRef(null);
  const messagesEndRef = useRef(null);
  const messagesContainerRef = useRef(null);

  useEffect(() => {
    const storedUser = localStorage.getItem("chatUser");
    const storedToken = localStorage.getItem("chatToken");
    if (storedUser && storedToken) {
      setUsername(storedUser);
      setToken(storedToken);
      joinRoom("global");
    }
  }, []);

  const joinRoom = (selectedRoom) => {
    setRoom(selectedRoom);
    socket.emit("joinRoom", { username, room: selectedRoom });
    fetchMessages(selectedRoom);
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    try {
      const url = `${SERVER_URL}/${mode}`;
      const res = await axios.post(url, form);
      setUsername(res.data.username);
      setToken(res.data.token);
      localStorage.setItem("chatUser", res.data.username);
      localStorage.setItem("chatToken", res.data.token);
      joinRoom("global");
    } catch (err) {
      alert(err.response?.data?.error || "Auth failed");
    }
  };

  const handleLogout = () => {
    setUsername(null);
    setToken(null);
    localStorage.removeItem("chatUser");
    localStorage.removeItem("chatToken");
  };

  const fetchMessages = async (selectedRoom) => {
    try {
      const res = await axios.get(`${SERVER_URL}/messages/${selectedRoom}`);
      setMessages(res.data);
    } catch (err) {
      console.error("Failed to fetch messages:", err);
    }
  };

  useEffect(() => {
    socket.on("receiveMessage", (message) => {
      if (message.room === room) setMessages((prev) => [...prev, message]);
    });
    socket.on("onlineUsers", (users) => setOnlineUsers(users));
    socket.on("typing", (data) => {
      if (data && data.room === room) setTypingUser(data.username);
    });
    socket.on("stopTyping", (data) => {
      if (data && data.room === room) setTypingUser(null);
    });

    return () => {
      socket.off("receiveMessage");
      socket.off("onlineUsers");
      socket.off("typing");
      socket.off("stopTyping");
    };
  }, [room]);

  const sendMessage = (e) => {
    e.preventDefault();
    if (!text.trim()) return;
    socket.emit("sendMessage", { username, text, room });
    setText("");
    socket.emit("stopTyping", { room });
  };

  const handleTyping = (e) => {
    setText(e.target.value);
    if (username) {
      socket.emit("typing", { username, room });
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = setTimeout(() => {
        socket.emit("stopTyping", { room });
      }, 1000);
    }
  };

  if (!username) {
    return (
      <div className="app">
        <div className="login">
          <h2>{mode === "login" ? "Login" : "Signup"}</h2>
          <form onSubmit={handleAuth}>
            <input type="text" placeholder="Username"
              value={form.username}
              onChange={(e) => setForm({ ...form, username: e.target.value })} />
            {mode === "signup" && (
              <input type="email" placeholder="Email"
                value={form.email || ""}
                onChange={(e) => setForm({ ...form, email: e.target.value })} />
            )}
            <input type="password" placeholder="Password"
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })} />
            <button type="submit">{mode === "login" ? "Login" : "Signup"}</button>
          </form>
          <p>
            {mode === "login" ? "Don't have an account?" : "Already registered?"}{" "}
            <button onClick={() => setMode(mode === "login" ? "signup" : "login")} className="link">
              {mode === "login" ? "Signup" : "Login"}
            </button>
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2>Welcome, {username} 👋</h2>
        <button className="logout" onClick={handleLogout}>Logout</button>
      </div>

      <div className="chat-main">
        <div className="sidebar">
          <h4>Rooms</h4>
          <ul>
            <li onClick={() => joinRoom("global")}>Global</li>
            {["Sports", "Tech", "Movies"].map((r, i) => (
              <li key={i} onClick={() => joinRoom(r)}>{r}</li>
            ))}
          </ul>
          <input value={newRoom} onChange={(e) => setNewRoom(e.target.value)} placeholder="New room..." />
          <button onClick={() => { if (newRoom.trim()) { joinRoom(newRoom.trim()); setNewRoom(""); } }}>Create Room</button>

          <h4>Online Users</h4>
          <ul>{onlineUsers.map((u, i) => <li key={i}>{u}</li>)}</ul>
        </div>

        <div className="messages-area">
          <div className="messages" ref={messagesContainerRef}>
            {messages.map((msg, i) => (
              <div key={i} className={`message ${msg.username === username ? "me" : "other"}`}>
                <div className="text">
                  {msg.username !== username && <strong>{msg.username}: </strong>}
                  {msg.text}
                  <span className="timestamp">{new Date(msg.createdAt).toLocaleTimeString()}</span>
                </div>
              </div>
            ))}
            <div ref={messagesEndRef} />
          </div>

          {typingUser && <div className="typing">{typingUser} is typing...</div>}

          <form className="composer" onSubmit={sendMessage}>
            <textarea value={text} onChange={handleTyping} placeholder="Type a message..." />
            <button type="submit">Send</button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default App;
